mapper.select:
/* SQL ID : ExamAbsentDAO.list 설 명 : 결시원 리스트 조회 */ SELECT ROW_NUMBER() OVER(ORDER BY C.USERNM DESC, A.REG_DTTM) AS LINE_NO , A.EXAM_ABSNCE_ID , A.SBJCT_ID , A.EXAM_ID , A.STD_ID , A.ABSNCE_TTL , A.ABSNCE_CTS , A.APRV_STSCD , A.APRV_CTS , A.MNGR_OPNN , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.MDFR_ID) AS MOD_NM , A.MOD_DTTM , C.DEPTNM , C.USER_ID , C.USERNM , C.MOBILE_NO , C.EMAIL , D.SBJCTNM , D.DVCLAS_NO , E.TKEXAM_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = E.ORG_ID AND CTGRCD = 'EXAM_STARE_UNI_CD' AND CD = E.TKEXAM_TYCD) AS EXAM_STARE_TYPE_NM , COUNT(1) OVER() AS TOTAL_CNT
, CASE WHEN (SELECT MAX(APRV_STSCD) KEEP (DENSE_RANK FIRST ORDER BY REG_DTTM DESC) FROM TB_LMS_EXAM_ABSNCE WHERE SBJCT_ID = A.SBJCT_ID AND EXAM_ID = A.EXAM_ID AND STD_ID = A.STD_ID) != 'COMPANION' THEN 'Y' ELSE 'N' END AS RE_APPLICATE_YN , CASE WHEN NVL((SELECT STARE_CNT FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = A.EXAM_ID AND STD_ID = B.STD_ID), 0) = 0 THEN 'N' ELSE 'Y' END AS EXAM_STARE_YN , B.GDSC_DGRS_CRS_GBNCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = B.ORG_ID AND CTGRCD = 'GDSC_DGRS_CRS_GBNCD' AND CD = B.GDSC_DGRS_CRS_GBNCD) AS GRSC_DEGR_CORS_GBN_NM FROM TB_LMS_EXAM_ABSNCE A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID AND A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD NOT IN('D', 'T') JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_SBJCT D ON A.SBJCT_ID = D.SBJCT_ID JOIN TB_LMS_EXAM_BSC E ON A.EXAM_ID = E.EXAM_ID WHERE 1 = 1
AND A.SBJCT_ID = #{crsCreCd}
AND A.EXAM_ABSNCE_ID IN (SELECT EXAM_ABSNCE_ID FROM (SELECT AA.EXAM_ABSNCE_ID, ROW_NUMBER() OVER(PARTITION BY AA.STD_ID ORDER BY AA.REG_DTTM DESC) AS RN FROM TB_LMS_EXAM_ABSNCE AA WHERE AA.SBJCT_ID = #{crsCreCd}) WHERE RN = 1)
AND A.SBJCT_ID IN (SELECT SBJCT_ID FROM SBJCT_PROF WHERE USER_ID = #{searchFrom} AND SBJCT_ID IN (SELECT SBJCT_ID FROM TB_LMS_SBJCT WHERE SBJCT_ID = #{creYear} AND CRS_ID = #{creTerm} AND DELYN = 'N'))
AND A.STD_ID = #{stdNo}
AND E.TKEXAM_TYCD = #{examStareTypeCd}
AND A.APRV_STSCD = #{apprStat}
AND ( LOWER(C.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND D.SBJCT_ID = #{creYear}
AND D.CRS_ID = #{creTerm}
AND B.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = #{rgtrId} AND ATNDLC_STSCD != 'D')
ORDER BY C.USERNM, A.REG_DTTM DESC

/* SQL ID : ExamAbsentDAO.listPaging 설 명 : 결시원 리스트 조회 페이징 */
SELECT * FROM (
SELECT A.* FROM ( SELECT ROW_NUMBER() OVER (ORDER BY A.REG_DTTM) AS LINE_NO, COUNT(1) OVER () AS TOTAL_CNT, A.* FROM ( SELECT ROW_NUMBER() OVER (PARTITION BY TLEA.EXAM_BSC_ID, TLEA.USER_ID ORDER BY TLEA.REG_DTTM DESC) AS RN , TLS.SBJCT_YR , TLS.SBJCT_SMSTR , TLS.CRS_ID , TLEA.USER_ID , (SELECT USERNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = TLEA.USER_ID) AS USERNM , '' AS 분반 , TLEA.APRV_STSCD , TLEA.REG_DTTM , EXAM_TYCD , '' AS 실시간시험응시여부 , TLEA.APRV_DTTM , TLEA.ATHRZR_ID FROM TB_LMS_EXAM_BSC TLEB JOIN TB_LMS_EXAM_ABSNCE TLEA ON TLEB.EXAM_BSC_ID = TLEA.EXAM_BSC_ID JOIN TB_LMS_SBJCT TLS ON TLEB.SBJCT_ID = TLS.SBJCT_ID WHERE 1=1
AND A.STD_ID = #{stdId}
AND E.TKEXAM_TYCD = #{examStareTypeCd}
AND ( LOWER(C.DEPTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND TLS.SBJCT_YR = #{creYear}
AND TLS.SBJCT_SMSTR = #{creTerm}
) A WHERE A.RN = 1
AND A.APRV_STSCD IN ('APPLICATE', 'RAPPLICATE')
AND A.APRV_STSCD = #{apprStat}
) A ORDER BY A.REG_DTTM DESC
) WHERE LINE_NO BETWEEN #{firstIndex} AND #{listScale}

/* SQL ID : ExamAbsentDAO.select 설 명 : 결시원 정보 조회 */ SELECT * FROM ( SELECT EXAM_ABSNCE_ID AS examAbsentCd , A.SBJCT_ID AS crsCreCd , A.EXAM_ID AS examCd , A.STD_ID AS stdNo , A.ABSNCE_TTL AS absentTitle , A.ABSNCE_CTS AS absentCts , A.APRV_STSCD AS apprStat , A.APRV_CTS AS apprCts , A.MNGR_OPNN AS mgrCmnt , A.RGTR_ID AS rgtrId , A.REG_DTTM AS regDttm , A.MDFR_ID AS mdfrId , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.MDFR_ID) AS modNm , A.MOD_DTTM AS modDttm , C.DEPT_CD AS deptCd , C.DEPTNM AS deptNm , C.EMAIL AS email , C.USER_ID AS userId , C.USERNM AS userNm , C.MOBILE_NO AS mobileNo , D.CRS_ID AS crsCd , D.SBJCTNM AS crsCreNm , D.DVCLAS_NO AS declsNo , E.TKEXAM_TYCD AS examStareTypeCd , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = E.ORG_ID AND CTGRCD = 'EXAM_STARE_UNI_CD' AND CD = E.TKEXAM_TYCD) AS examStareTypeNm , E.EXAM_SDTTM AS examStartDttm , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = (SELECT AA.USER_ID FROM SBJCT_PROF AA WHERE AA.SBJCT_ID = D.SBJCT_ID AND AA.PROF_TYCD = 'PROFESSOR' AND AA.RPRSYN = 'Y')) AS tchNm , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = ( SELECT USER_ID FROM ( SELECT AA.USER_ID FROM SBJCT_PROF AA , TB_LMS_SBJCT D WHERE AA.SBJCT_ID = D.SBJCT_ID AND AA.PROF_TYCD = 'ASSISTANT' ) WHERE ROWNUM = 1) ) AS tutorNm, (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE DEPT_CD = D.DEPT_CD AND ORG_ID = C.ORG_ID AND USEYN = 'Y') AS crsDeptNm , CASE WHEN NVL((SELECT STARE_CNT FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = A.EXAM_ID AND STD_ID = B.STD_ID), 0) = 0 THEN 'N' ELSE 'Y' END AS examStareYn FROM TB_LMS_EXAM_ABSNCE A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID AND A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD NOT IN('D', 'T') JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_SBJCT D ON A.SBJCT_ID = D.SBJCT_ID JOIN TB_LMS_EXAM_BSC E ON A.EXAM_ID = E.EXAM_ID WHERE 1 = 1
AND A.EXAM_ABSNCE_ID = #{examAbsentCd}
AND A.EXAM_ID = #{examCd}
AND A.STD_ID = #{stdNo}
AND A.SBJCT_ID = #{crsCreCd}
ORDER BY A.REG_DTTM DESC ) WHERE ROWNUM = 1

/* SQL ID : ExamAbsentDAO.listMyCreCrsExamAbsent 설 명 : 내 강의에 등록된 결시원 리스트 조회 */ SELECT ROW_NUMBER() OVER(ORDER BY A.SBJCT_ID, A.TKEXAM_TYCD, A.REG_DTTM) AS lineNo , COUNT(1) OVER() AS totalCnt , A.* FROM ( SELECT ROW_NUMBER() OVER(PARTITION BY A.SBJCT_ID, D.EXAM_ID, B.STD_ID ORDER BY E.REG_DTTM DESC) AS RN , A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , B.STD_ID , E.APRV_STSCD , E.MNGR_OPNN , E.REG_DTTM , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = E.MDFR_ID) AS modNm , E.MOD_DTTM , E.EXAM_ABSNCE_ID , D.EXAM_ID , D.TKEXAM_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = D.ORG_ID AND CTGRCD = 'EXAM_STARE_UNI_CD' AND CD = D.TKEXAM_TYCD) AS examStareTypeNm , CASE WHEN (SELECT APRV_STSCD FROM TB_LMS_EXAM_ABSNCE WHERE SBJCT_ID = E.SBJCT_ID AND EXAM_ID = E.EXAM_ID AND STD_ID = E.STD_ID ORDER BY REG_DTTM DESC LIMIT 1) != 'COMPANION' THEN 'Y' ELSE 'N' END AS reApplicateYn , CASE WHEN IFNULL((SELECT STARE_CNT FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = D.EXAM_ID AND STD_ID = B.STD_ID), 0) = 0 THEN 'N' ELSE 'Y' END AS examStareYn FROM TB_LMS_SBJCT AS A JOIN TB_LMS_ATNDLC_SBJCT AS B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD NOT IN('D', 'T') AND A.DELYN = 'N' JOIN TB_LMS_EXAM_CRE_CRS_RLTN AS C ON C.SBJCT_ID = A.SBJCT_ID AND C.DELYN = 'N' JOIN TB_LMS_EXAM_BSC AS D ON C.EXAM_ID = D.EXAM_ID AND D.EXAM_CTGRCD = 'EXAM' AND D.EXAM_TYCD = 'EXAM' AND D.TKEXAM_TYCD IN ('M', 'L') AND ( ( D.TKEXAM_TYCD = 'M' AND EXISTS (SELECT 1 FROM TB_LMS_SYSJOB_SCHDL WHERE DGRS_YR = #{creYear} AND DGRS_SMSTR = #{creTerm} AND SYSJOB_SCHDL_TYCD = '00190904' -- 결시원신청-학생(중간고사) AND FN_DTTM() >= SYSJOB_SCHDL_SYMD ) ) OR ( D.TKEXAM_TYCD = 'L' AND EXISTS (SELECT 1 FROM TB_LMS_SYSJOB_SCHDL WHERE DGRS_YR = #{creYear} AND DGRS_SMSTR = #{creTerm} AND SYSJOB_SCHDL_TYCD = '00190905' -- 결시원신청-학생(기말고사) AND FN_DTTM() >= SYSJOB_SCHDL_SYMD ) ) ) LEFT JOIN TB_LMS_EXAM_ABSNCE AS E ON B.STD_ID = E.STD_ID AND A.SBJCT_ID = E.SBJCT_ID AND D.EXAM_ID = E.EXAM_ID WHERE B.USER_ID = #{userId}
AND A.SBJCT_ID = #{creYear}
AND A.CRS_ID = #{creTerm}
AND LOWER(A.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
) A WHERE RN = 1
AND A.APRV_STSCD IN ('APPLICATE', 'RAPPLICATE')
AND A.APRV_STSCD = #{apprStat}
ORDER BY A.SBJCT_ID DESC, A.TKEXAM_TYCD DESC, A.REG_DTTM DESC

mapper.insert:
/*
     SQL ID : ExamAbsentDAO.insertAbsent
     설  명 : 결시원 등록
 */
INSERT INTO TB_LMS_EXAM_ABSNCE (
      EXAM_ABSNCE_ID
    , SBJCT_ID
    , EXAM_ID
    , STD_ID
    , ABSNCE_TTL
    , ABSNCE_CTS
    , APRV_STSCD
    , APRV_CTS
    , MNGR_OPNN
    , RGTR_ID
    , REG_DTTM
    , MDFR_ID
    , MOD_DTTM
) VALUES (
      #{examAbsentCd}
    , #{crsCreCd}
    , #{examCd}
    , #{stdNo}
    , #{absentTitle}
    , #{absentCts}
    , #{apprStat}
    , #{apprCts}
    , #{mgrCmnt}
    , #{rgtrId}
    , FN_DTTM()
    , #{mdfrId}
    , FN_DTTM()
)

mapper.update:
/*
     SQL ID : ExamAbsentDAO.updateAbsent
     설  명 : 결시원 수정
 */
UPDATE TB_LMS_EXAM_ABSNCE
   SET MDFR_ID 		= #{mdfrId}
       , MOD_DTTM 		= FN_DTTM()

        , ABSNCE_TTL = #{absentTitle}


        , ABSNCE_CTS = #{absentCts}


        , APRV_STSCD = #{apprStat}


        , APRV_CTS = #{apprCts}


        , MNGR_OPNN = #{mgrCmnt}

WHERE EXAM_ABSNCE_ID = #{examAbsentCd}

mapper.select:
/* SQL ID : ExamAbsentDAO.listAdminExamAbsent 설 명 : 관리자 > 결시원 리스트 조회 */ SELECT ROW_NUMBER() OVER(ORDER BY A.REG_DTTM DESC) AS lineNo , A.* , CASE WHEN (SELECT APRV_STSCD FROM TB_LMS_EXAM_ABSNCE WHERE EXAM_ABSNCE_ID = A.EXAM_ABSNCE_ID) != 'COMPANION' THEN 'Y' ELSE 'N' END AS reApplicateYn FROM (SELECT ROW_NUMBER() OVER(PARTITION BY B.SBJCT_ID, E.EXAM_ID, B.STD_ID ORDER BY A.REG_DTTM DESC) AS RN , A.EXAM_ABSNCE_ID , B.STD_ID , C.DEPTNM , C.USER_ID , C.USERNM , D.SBJCT_ID , D.SBJCTNM , D.CRS_ID , D.DVCLAS_NO , NVL(( SELECT AA.USER_ID FROM SBJCT_PROF AA WHERE AA.PROF_TYCD = 'PROFESSOR' AND AA.RPRSYN = 'Y' AND AA.SBJCT_ID = A.SBJCT_ID ), '-') AS tchNo , NVL(( SELECT (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = AA.USER_ID) FROM SBJCT_PROF AA WHERE AA.PROF_TYCD = 'PROFESSOR' AND AA.RPRSYN = 'Y' AND AA.SBJCT_ID = A.SBJCT_ID ), '-') AS tchNm , NVL(( SELECT LISTAGG(AA.USER_ID) WITHIN GROUP ( ORDER BY AA.USER_ID ) FROM SBJCT_PROF AA WHERE AA.PROF_TYCD = 'ASSISTANT' AND AA.SBJCT_ID = A.SBJCT_ID ), '-') AS tutorNo , NVL(( SELECT LISTAGG( (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = AA.USER_ID)) WITHIN GROUP ( ORDER BY USERNM ) FROM SBJCT_PROF AA WHERE AA.PROF_TYCD = 'ASSISTANT' AND AA.SBJCT_ID = A.SBJCT_ID ), '-') AS tutorNm , A.APRV_STSCD , A.MNGR_OPNN , CASE A.APRV_STSCD WHEN 'APPLICATE' THEN '신청' WHEN 'RAPPLICATE' THEN '재신청' WHEN 'APPROVE' THEN '승인' WHEN 'COMPANION' THEN '반려' END AS apprStatNm , A.REG_DTTM , E.TKEXAM_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = E.ORG_ID AND CTGRCD = 'EXAM_STARE_UNI_CD' AND CD = E.TKEXAM_TYCD) AS examStareTypeNm , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.MDFR_ID) AS modNm , A.MOD_DTTM , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE DEPT_CD = D.DEPT_CD AND ORG_ID = #{orgId} AND USEYN = 'Y') AS crsDeptNm , C.MOBILE_NO , C.EMAIL , CASE WHEN NVL((SELECT STARE_CNT FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = A.EXAM_ID AND STD_ID = B.STD_ID), 0) = 0 THEN 'N' ELSE 'Y' END AS examStareYn , NVL((SELECT 'Y' FROM TB_LMS_EXAM_BSC WHERE EXAM_ID = A.EXAM_ID AND EXAM_SBST_REF_ID IS NOT NULL), 'N') AS examSubsYn FROM TB_LMS_EXAM_ABSNCE A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID AND A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD NOT IN('D', 'T') JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_SBJCT D ON A.SBJCT_ID = D.SBJCT_ID JOIN TB_LMS_EXAM_BSC E ON A.EXAM_ID = E.EXAM_ID WHERE 1 = 1
AND D.SBJCT_ID = #{creYear}
AND D.CRS_ID = #{creTerm}
AND B.ORG_ID = #{orgId}
AND D.DEPT_CD = #{deptCd}
AND D.SBJCT_ID = #{crsCreCd}
AND E.TKEXAM_TYCD = #{examStareTypeCd}
AND C.USER_ID = #{userId}
AND LOWER(C.USERNM) LIKE CONCAT('%', LOWER(#{userNm}), '%') COLLATE utf8mb4_general_ci
AND D.UNIV_CD = #{uniCd}
AND D.UNIV_GBNCD = #{univGbn}
AND ( LOWER(D.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(D.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(C.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
) A WHERE RN = 1
AND A.APRV_STSCD IN ('APPLICATE', 'RAPPLICATE')
AND A.APRV_STSCD = #{apprStat}
AND ( LOWER(A.tchNo) LIKE '%' || LOWER(#{tchNo}) || '%' OR LOWER(A.tutorNo) LIKE '%' || LOWER(#{tchNo}) || '%' )
AND ( LOWER(A.tchNm) LIKE '%' || LOWER(#{tchNm}) || '%' OR LOWER(A.tutorNm) LIKE '%' || LOWER(#{tchNm}) || '%' )

/* SQL ID : ExamAbsentDAO.listAllStuAbsentExam 설 명 : 학생 전체 결시원 대상 시험 리스트 조회 */ SELECT A.SBJCT_ID , A.DEPT_CD , A.CRS_ID , A.SBJCTNM , A.DVCLAS_NO , B.STD_ID , D.EXAM_ID , D.EXAM_SDTTM , D.TKEXAM_TYCD , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = #{orgId} AND DEPT_CD = A.DEPT_CD) AS DEPTNM , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = E.USER_ID) AS TCH_NM
, (SELECT APRV_STSCD FROM TB_LMS_EXAM_ABSNCE WHERE SBJCT_ID = A.SBJCT_ID AND EXAM_ID = D.EXAM_ID AND STD_ID = B.STD_ID) AS APRV_STSCD , (SELECT EXAM_ABSNCE_ID FROM TB_LMS_EXAM_ABSNCE WHERE SBJCT_ID = A.SBJCT_ID AND EXAM_ID = D.EXAM_ID AND STD_ID = B.STD_ID) AS EXAM_ABSNCE_ID , (SELECT REG_DTTM FROM TB_LMS_EXAM_ABSNCE WHERE SBJCT_ID = A.SBJCT_ID AND EXAM_ID = D.EXAM_ID AND STD_ID = B.STD_ID) AS REG_DTTM , (SELECT MOD_DTTM FROM TB_LMS_EXAM_ABSNCE WHERE SBJCT_ID = A.SBJCT_ID AND EXAM_ID = D.EXAM_ID AND STD_ID = B.STD_ID) AS MOD_DTTM , CASE WHEN NVL((SELECT STARE_CNT FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = D.EXAM_ID AND STD_ID = B.STD_ID), 0) = 0 THEN 'N' ELSE 'Y' END AS examStareYn FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.USER_ID = #{userId} AND B.ORG_ID = #{orgId} JOIN TB_LMS_EXAM_CRE_CRS_RLTN C ON C.SBJCT_ID = A.SBJCT_ID AND C.DELYN = 'N' JOIN TB_LMS_EXAM_BSC D ON C.EXAM_ID = D.EXAM_ID AND D.EXAM_CTGRCD = 'EXAM' AND D.EXAM_TYCD = 'EXAM' AND D.TKEXAM_TYCD IN ('M', 'L') LEFT JOIN SBJCT_PROF E ON A.SBJCT_ID = E.SBJCT_ID AND E.PROF_TYCD = 'PROFESSOR' AND E.RPRSYN = 'Y' WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{creYear} AND A.CRS_ID = #{creTerm}
AND A.SBJCT_ID = #{crsCreCd}
ORDER BY A.SBJCTNM, A.DVCLAS_NO, D.TKEXAM_TYCD DESC
